/* ---------------------------------------------------------------
 * Patch UI design tokens.
 *
 * The system design is inspired by Vercel Geist (https://vercel.com/geist):
 * the 100 -> 1000 scale structure with a consistent intent per step,
 * the palette selection (gray + 7 accents), the four-family typography
 * scale (heading / copy / label / button), and the two-tone background
 * convention.
 *
 * The specific values vary in how close they are to Geist. Some
 * (e.g. --error / --warning / --success below) track Geist directly,
 * per inline comments. Others (the accent hue values, ten scale steps
 * per hue) are adaptations. The radius set, motion timings, and focus
 * ring approach are independent choices.
 *
 * What is ours: the Tailwind v4 four-layer implementation below
 * (raw vars -> @theme inline bridge -> compound utility classes ->
 * base element styles), the check:contrast gate, and every
 * downstream component built on top.
 *
 * See apps/docs/src/app/docs/credits/page.mdx for the full attribution.
 *
 * ---------------------------------------------------------------
 * Layer 1: Runtime theme values
 *
 * Every token is defined here as a raw CSS custom property.
 * Components consume them directly (var(--gray-1000)) or via
 * utility classes generated by the @theme block below.
 *
 * Contract:
 *   Gray + accent scales run 100 -> 1000 with intent:
 *     100 fill, 200 hover, 300 active,
 *     400 border, 500 hover border, 600 active border,
 *     700 solid, 800 solid hover,
 *     900 secondary text, 1000 primary text
 *   Backgrounds are a separate 100/200 scale.
 *   Contrast: 1000 vs 100 must clear AAA; 700+ vs 100 must clear AA.
 * --------------------------------------------------------------- */
:root {
  /* Backgrounds */
  --background-100: #ffffff;
  --background-200: #fafafa;

  /* Gray scale */
  --gray-100: #f2f2f2;
  --gray-200: #ebebeb;
  --gray-300: #e0e0e0;
  --gray-400: #d1d1d1;
  --gray-500: #b8b8b8;
  --gray-600: #8f8f8f;
  --gray-700: #737373;
  --gray-800: #525252;
  --gray-900: #333333;
  --gray-1000: #171717;

  /* Gray alpha (translucent, sits on any background) */
  --gray-alpha-100: rgba(0, 0, 0, 0.05);
  --gray-alpha-200: rgba(0, 0, 0, 0.08);
  --gray-alpha-300: rgba(0, 0, 0, 0.10);
  --gray-alpha-400: rgba(0, 0, 0, 0.13);
  --gray-alpha-500: rgba(0, 0, 0, 0.20);
  --gray-alpha-600: rgba(0, 0, 0, 0.30);
  --gray-alpha-700: rgba(0, 0, 0, 0.45);
  --gray-alpha-800: rgba(0, 0, 0, 0.60);
  --gray-alpha-900: rgba(0, 0, 0, 0.80);
  --gray-alpha-1000: rgba(0, 0, 0, 0.90);

  /* Blue */
  --blue-100: #edf5ff;
  --blue-200: #d6e6ff;
  --blue-300: #adc9ff;
  --blue-400: #7aa8ff;
  --blue-500: #4d8bff;
  --blue-600: #2470ff;
  --blue-700: #006bff;
  --blue-800: #0057d1;
  --blue-900: #003fa3;
  --blue-1000: #002966;

  /* Red */
  --red-100: #fdf0f0;
  --red-200: #fbdada;
  --red-300: #f4b0b0;
  --red-400: #ec8080;
  --red-500: #e05252;
  --red-600: #d43232;
  --red-700: #c31313;
  --red-800: #9c0f0f;
  --red-900: #720a0a;
  --red-1000: #440505;

  /* Amber */
  --amber-100: #fff7e0;
  --amber-200: #ffebb8;
  --amber-300: #fdd77a;
  --amber-400: #f6bd3d;
  --amber-500: #e6a41f;
  --amber-600: #cc8c00;
  --amber-700: #8f6300;
  --amber-800: #7f5800;
  --amber-900: #593d00;
  --amber-1000: #332300;

  /* Green */
  --green-100: #e6f7ec;
  --green-200: #c7ecd5;
  --green-300: #94dcaf;
  --green-400: #5fc884;
  --green-500: #33b25f;
  --green-600: #15963f;
  --green-700: #007a2e;
  --green-800: #005f24;
  --green-900: #00461b;
  --green-1000: #002912;

  /* Teal */
  --teal-100: #e0f7f3;
  --teal-200: #bcecdf;
  --teal-300: #7ddcc0;
  --teal-400: #40c8a2;
  --teal-500: #14b088;
  --teal-600: #009170;
  --teal-700: #00755b;
  --teal-800: #005b47;
  --teal-900: #004234;
  --teal-1000: #00261e;

  /* Purple */
  --purple-100: #f4eeff;
  --purple-200: #e1d1ff;
  --purple-300: #c6a8ff;
  --purple-400: #a67dff;
  --purple-500: #8b57ff;
  --purple-600: #7233ff;
  --purple-700: #5b1cd6;
  --purple-800: #4514a3;
  --purple-900: #300d75;
  --purple-1000: #1b0745;

  /* Pink */
  --pink-100: #ffedf5;
  --pink-200: #ffd1e5;
  --pink-300: #ffa2ca;
  --pink-400: #ff70ac;
  --pink-500: #ff408e;
  --pink-600: #eb1a70;
  --pink-700: #c50057;
  --pink-800: #970044;
  --pink-900: #6d0031;
  --pink-1000: #40001d;

  /* Semantic role aliases: fixed hex so status colors read the same
     in both themes. Status intent (destructive, warning, success)
     doesn't shift meaning between light and dark, so the fill shouldn't
     either. Values pulled from Vercel Geist red/amber/blue-800. */
  /* Semantic status solids for Badge/Button/etc. Theme-aware: light mode
     uses the darker end of each hue with light (white) text; dark mode
     uses the lighter end with dark text. Matches Vercel Geist's rendered
     Badge palette across both modes. Each role has a paired *-fg token
     that carries the label color, so the fill and text invert together
     per theme without a callsite dark: variant. See Badge/Button for
     usage. */
  /* Values pixel-sampled from Vercel Geist's rendered Badge screenshots.
     Warning is theme-invariant (bright amber + dark text works in both).
     Error and Success shift a step brighter in dark mode; label text
     flips accordingly via the -fg pair. */
  --error: #dc2626;
  --error-hover: #b91c1c;
  --error-active: #991b1b;
  --error-fg: #ffffff;
  --warning: #fdb203;
  --warning-hover: #d69800;
  --warning-active: #a97007;
  --warning-fg: #171717;
  --success: #397c3b;
  --success-hover: #2d602d;
  --success-active: #234a23;
  --success-fg: #ffffff;

  /* Radius */
  --radius-6: 6px;
  --radius-12: 12px;
  --radius-16: 16px;
  --radius-full: 9999px;

  /* Shadows (light-mode stacks) */
  --shadow-card: 0 2px 2px rgba(0, 0, 0, 0.04);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 4px 8px -4px rgba(0, 0, 0, 0.04),
    0 16px 24px -8px rgba(0, 0, 0, 0.06);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 8px 16px -4px rgba(0, 0, 0, 0.04),
    0 24px 32px -8px rgba(0, 0, 0, 0.06);
  --shadow-tooltip: var(--shadow-menu);

  /* Motion (twist: 50% of reference timings) */
  --ease-standard: cubic-bezier(0.175, 0.885, 0.32, 1.1);
  --duration-state: 75ms;
  --duration-overlay: 150ms;

  /* Focus (twist: 1px neutral outline) */
  --focus-ring-color: var(--gray-alpha-600);
  --focus-ring-offset: 1px;

  /* Typography: heading family (weight 600) */
  --heading-72-size: 72px; --heading-72-leading: 1.05; --heading-72-tracking: -0.045em; --heading-72-weight: 600;
  --heading-64-size: 64px; --heading-64-leading: 1.05; --heading-64-tracking: -0.04em;  --heading-64-weight: 600;
  --heading-56-size: 56px; --heading-56-leading: 1.08; --heading-56-tracking: -0.04em;  --heading-56-weight: 600;
  --heading-48-size: 48px; --heading-48-leading: 1.1;  --heading-48-tracking: -0.035em; --heading-48-weight: 600;
  --heading-40-size: 40px; --heading-40-leading: 1.15; --heading-40-tracking: -0.035em; --heading-40-weight: 600;
  --heading-32-size: 32px; --heading-32-leading: 1.2;  --heading-32-tracking: -0.03em;  --heading-32-weight: 600;
  --heading-24-size: 24px; --heading-24-leading: 1.25; --heading-24-tracking: -0.025em; --heading-24-weight: 600;
  --heading-20-size: 20px; --heading-20-leading: 1.3;  --heading-20-tracking: -0.02em;  --heading-20-weight: 600;
  --heading-16-size: 16px; --heading-16-leading: 1.4;  --heading-16-tracking: -0.015em; --heading-16-weight: 600;
  --heading-14-size: 14px; --heading-14-leading: 1.4;  --heading-14-tracking: -0.01em;  --heading-14-weight: 600;

  /* Typography: label family (weight 400) */
  --label-20-size: 20px; --label-20-leading: 1.4; --label-20-tracking: -0.015em; --label-20-weight: 400;
  --label-18-size: 18px; --label-18-leading: 1.4; --label-18-tracking: -0.015em; --label-18-weight: 400;
  --label-16-size: 16px; --label-16-leading: 1.4; --label-16-tracking: -0.011em; --label-16-weight: 400;
  --label-14-size: 14px; --label-14-leading: 1.4; --label-14-tracking: -0.006em; --label-14-weight: 400;
  --label-13-size: 13px; --label-13-leading: 1.4; --label-13-tracking: -0.005em; --label-13-weight: 400;
  --label-12-size: 12px; --label-12-leading: 1.35; --label-12-tracking: 0;       --label-12-weight: 400;
  /* Caption tier: below Geist's public scale, used for section headers
     inside dense surfaces (Command sections, Table column headers, Card
     meta lines). Tracking opens slightly at these small sizes to keep
     the letters legible. */
  --label-11-size: 11px; --label-11-leading: 1.35; --label-11-tracking: 0.005em; --label-11-weight: 400;
  --label-10-size: 10px; --label-10-leading: 1.35; --label-10-tracking: 0.01em;  --label-10-weight: 400;

  /* Typography: copy family (weight 400) */
  --copy-24-size: 24px; --copy-24-leading: 1.5; --copy-24-tracking: -0.02em;  --copy-24-weight: 400;
  --copy-20-size: 20px; --copy-20-leading: 1.5; --copy-20-tracking: -0.015em; --copy-20-weight: 400;
  --copy-18-size: 18px; --copy-18-leading: 1.55; --copy-18-tracking: -0.013em; --copy-18-weight: 400;
  --copy-16-size: 16px; --copy-16-leading: 1.6; --copy-16-tracking: -0.011em; --copy-16-weight: 400;
  --copy-14-size: 14px; --copy-14-leading: 1.55; --copy-14-tracking: -0.006em; --copy-14-weight: 400;
  --copy-13-size: 13px; --copy-13-leading: 1.5; --copy-13-tracking: -0.005em; --copy-13-weight: 400;

  /* Typography: button family (weight 500) */
  --button-16-size: 16px; --button-16-leading: 1; --button-16-tracking: -0.011em; --button-16-weight: 500;
  --button-14-size: 14px; --button-14-leading: 1; --button-14-tracking: -0.006em; --button-14-weight: 500;
  --button-12-size: 12px; --button-12-leading: 1; --button-12-tracking: 0;        --button-12-weight: 500;

  /* Spacing scale */
  --space-4: 4px;
  --space-8: 8px;
  --space-12: 12px;
  --space-16: 16px;
  --space-24: 24px;
  --space-32: 32px;
  --space-40: 40px;
  --space-64: 64px;
  --space-96: 96px;
}

/* Dark-mode override. Same intent contract, inverted values. */
.dark {
  /* Vercel Geist approach: dark surfaces share the canvas color (#000).
     Distinction between page / card / modal comes from the border +
     shadow, not brightness. background-200 is the lightly-elevated
     variant used for footer bars, subtle callouts, and code blocks. */
  --background-100: #000000;
  --background-200: #0a0a0a;

  --gray-100: #1f1f1f;
  --gray-200: #2a2a2a;
  --gray-300: #333333;
  --gray-400: #3d3d3d;
  --gray-500: #575757;
  --gray-600: #7a7a7a;
  --gray-700: #999999;
  --gray-800: #b8b8b8;
  --gray-900: #d1d1d1;
  --gray-1000: #ededed;

  --gray-alpha-100: rgba(255, 255, 255, 0.05);
  --gray-alpha-200: rgba(255, 255, 255, 0.08);
  --gray-alpha-300: rgba(255, 255, 255, 0.10);
  --gray-alpha-400: rgba(255, 255, 255, 0.13);
  --gray-alpha-500: rgba(255, 255, 255, 0.20);
  --gray-alpha-600: rgba(255, 255, 255, 0.30);
  --gray-alpha-700: rgba(255, 255, 255, 0.45);
  --gray-alpha-800: rgba(255, 255, 255, 0.60);
  --gray-alpha-900: rgba(255, 255, 255, 0.80);
  --gray-alpha-1000: rgba(255, 255, 255, 0.90);

  --blue-100: #001a3d; --blue-200: #002966; --blue-300: #003fa3; --blue-400: #0057d1; --blue-500: #006bff;
  --blue-600: #2f88ff; --blue-700: #5aa0ff; --blue-800: #85b8ff; --blue-900: #b8d3ff; --blue-1000: #e0eaff;

  --red-100: #2b0808; --red-200: #440505; --red-300: #720a0a; --red-400: #9c0f0f; --red-500: #c31313;
  --red-600: #dc4646; --red-700: #eb6b6b; --red-800: #f28a8a; --red-900: #f7b6b6; --red-1000: #fbdada;

  --amber-100: #2e2000; --amber-200: #4a3300; --amber-300: #6b4a00; --amber-400: #916500; --amber-500: #b57e00;
  --amber-600: #d99c00; --amber-700: #f2b83a; --amber-800: #f6cd6b; --amber-900: #fbdf99; --amber-1000: #fdefc7;

  --green-100: #002912; --green-200: #00461b; --green-300: #005f24; --green-400: #007a2e; --green-500: #15963f;
  --green-600: #33b25f; --green-700: #5fc884; --green-800: #94dcaf; --green-900: #c7ecd5; --green-1000: #e6f7ec;

  --teal-100: #00261e; --teal-200: #004234; --teal-300: #005b47; --teal-400: #00755b; --teal-500: #009170;
  --teal-600: #14b088; --teal-700: #40c8a2; --teal-800: #7ddcc0; --teal-900: #bcecdf; --teal-1000: #e0f7f3;

  --purple-100: #1b0745; --purple-200: #300d75; --purple-300: #4514a3; --purple-400: #5b1cd6; --purple-500: #7233ff;
  --purple-600: #8b57ff; --purple-700: #a67dff; --purple-800: #c6a8ff; --purple-900: #e1d1ff; --purple-1000: #f4eeff;

  --pink-100: #40001d; --pink-200: #6d0031; --pink-300: #970044; --pink-400: #c50057; --pink-500: #eb1a70;
  --pink-600: #ff408e; --pink-700: #ff70ac; --pink-800: #ffa2ca; --pink-900: #ffd1e5; --pink-1000: #ffedf5;

  /* Dark-mode semantic status. Values pixel-sampled from Vercel Geist:
     warning stays the same amber (theme-invariant), error and success
     shift a step brighter. Success is nudged slightly darker than
     Vercel's actual #3e933d so white text still clears AA. */
  --error: #cf3334;
  --error-hover: #b02020;
  --error-active: #971818;
  --error-fg: #ffffff;
  --warning: #fdb203;
  --warning-hover: #d69800;
  --warning-active: #a97007;
  --warning-fg: #171717;
  --success: #2d8438;
  --success-hover: #256d2e;
  --success-active: #1c5624;
  --success-fg: #ffffff;

  --shadow-card: 0 2px 2px rgba(0, 0, 0, 0.4);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 4px 8px -4px rgba(0, 0, 0, 0.4),
    0 16px 24px -8px rgba(0, 0, 0, 0.5);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 8px 16px -4px rgba(0, 0, 0, 0.4),
    0 24px 32px -8px rgba(0, 0, 0, 0.5);
}

/* P3 oklch overrides for accent hues where supported */
@supports (color: oklch(0 0 0)) {
  :root {
    --blue-700: oklch(0.56 0.24 262);
    --red-700: oklch(0.53 0.24 27);
    --amber-700: oklch(0.63 0.14 65);
    --green-700: oklch(0.55 0.17 148);
    --teal-700: oklch(0.55 0.13 175);
    --purple-700: oklch(0.55 0.24 288);
    --pink-700: oklch(0.55 0.24 355);
  }
  .dark {
    --blue-700: oklch(0.73 0.16 260);
    --red-700: oklch(0.7 0.18 25);
    --amber-700: oklch(0.78 0.15 75);
    --green-700: oklch(0.75 0.17 148);
    --teal-700: oklch(0.75 0.12 175);
    --purple-700: oklch(0.72 0.19 288);
    --pink-700: oklch(0.7 0.2 355);
  }
}

/* Loading dots: 3 dots pulse in staggered sequence */
@keyframes patch-dots-pulse {
  0%, 80%, 100% { opacity: 0.25; transform: scale(0.6); }
  40% { opacity: 1; transform: scale(1); }
}

/* Progress bar: indeterminate sweep from left to right */
@keyframes patch-progress-indeterminate {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(400%); }
}

/* Skeleton placeholder: gentle opacity pulse */
@keyframes patch-skeleton-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  :root {
    --duration-state: 0ms;
    --duration-overlay: 0ms;
    --ease-standard: ease;
  }
}

/* ---------------------------------------------------------------
 * Layer 2: Tailwind bridge (@theme inline)
 *
 * Each entry generates a utility class Tailwind can emit. We expose:
 *   - Every color token as --color-* (bg-gray-1000, text-blue-700, etc.)
 *   - Every radius as --radius-*
 *   - Every shadow as --shadow-*
 *   - Every spacing step as --spacing-*
 *   - Type sizes as --text-* (paired classes below for line/track/weight)
 *   - Easings and durations
 * --------------------------------------------------------------- */
@theme inline {
  --color-background-100: var(--background-100);
  --color-background-200: var(--background-200);

  --color-gray-100: var(--gray-100);
  --color-gray-200: var(--gray-200);
  --color-gray-300: var(--gray-300);
  --color-gray-400: var(--gray-400);
  --color-gray-500: var(--gray-500);
  --color-gray-600: var(--gray-600);
  --color-gray-700: var(--gray-700);
  --color-gray-800: var(--gray-800);
  --color-gray-900: var(--gray-900);
  --color-gray-1000: var(--gray-1000);

  --color-gray-alpha-100: var(--gray-alpha-100);
  --color-gray-alpha-200: var(--gray-alpha-200);
  --color-gray-alpha-300: var(--gray-alpha-300);
  --color-gray-alpha-400: var(--gray-alpha-400);
  --color-gray-alpha-500: var(--gray-alpha-500);
  --color-gray-alpha-600: var(--gray-alpha-600);
  --color-gray-alpha-700: var(--gray-alpha-700);
  --color-gray-alpha-800: var(--gray-alpha-800);
  --color-gray-alpha-900: var(--gray-alpha-900);
  --color-gray-alpha-1000: var(--gray-alpha-1000);

  --color-blue-100: var(--blue-100);   --color-blue-200: var(--blue-200);   --color-blue-300: var(--blue-300);
  --color-blue-400: var(--blue-400);   --color-blue-500: var(--blue-500);   --color-blue-600: var(--blue-600);
  --color-blue-700: var(--blue-700);   --color-blue-800: var(--blue-800);   --color-blue-900: var(--blue-900);
  --color-blue-1000: var(--blue-1000);

  --color-red-100: var(--red-100);     --color-red-200: var(--red-200);     --color-red-300: var(--red-300);
  --color-red-400: var(--red-400);     --color-red-500: var(--red-500);     --color-red-600: var(--red-600);
  --color-red-700: var(--red-700);     --color-red-800: var(--red-800);     --color-red-900: var(--red-900);
  --color-red-1000: var(--red-1000);

  --color-amber-100: var(--amber-100); --color-amber-200: var(--amber-200); --color-amber-300: var(--amber-300);
  --color-amber-400: var(--amber-400); --color-amber-500: var(--amber-500); --color-amber-600: var(--amber-600);
  --color-amber-700: var(--amber-700); --color-amber-800: var(--amber-800); --color-amber-900: var(--amber-900);
  --color-amber-1000: var(--amber-1000);

  --color-green-100: var(--green-100); --color-green-200: var(--green-200); --color-green-300: var(--green-300);
  --color-green-400: var(--green-400); --color-green-500: var(--green-500); --color-green-600: var(--green-600);
  --color-green-700: var(--green-700); --color-green-800: var(--green-800); --color-green-900: var(--green-900);
  --color-green-1000: var(--green-1000);

  --color-teal-100: var(--teal-100);   --color-teal-200: var(--teal-200);   --color-teal-300: var(--teal-300);
  --color-teal-400: var(--teal-400);   --color-teal-500: var(--teal-500);   --color-teal-600: var(--teal-600);
  --color-teal-700: var(--teal-700);   --color-teal-800: var(--teal-800);   --color-teal-900: var(--teal-900);
  --color-teal-1000: var(--teal-1000);

  --color-purple-100: var(--purple-100); --color-purple-200: var(--purple-200); --color-purple-300: var(--purple-300);
  --color-purple-400: var(--purple-400); --color-purple-500: var(--purple-500); --color-purple-600: var(--purple-600);
  --color-purple-700: var(--purple-700); --color-purple-800: var(--purple-800); --color-purple-900: var(--purple-900);
  --color-purple-1000: var(--purple-1000);

  --color-pink-100: var(--pink-100);   --color-pink-200: var(--pink-200);   --color-pink-300: var(--pink-300);
  --color-pink-400: var(--pink-400);   --color-pink-500: var(--pink-500);   --color-pink-600: var(--pink-600);
  --color-pink-700: var(--pink-700);   --color-pink-800: var(--pink-800);   --color-pink-900: var(--pink-900);
  --color-pink-1000: var(--pink-1000);

  --color-error: var(--error);
  --color-error-hover: var(--error-hover);
  --color-error-active: var(--error-active);
